INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('cc1f68b6-a294-5688-865e-a6c3144a7c77', '0d503313-f24a-4195-8140-6fd95a400606', 'This is my robot. ___ can talk.', '這是我的機器人。___會說話。', 'it', 'he', 'she', 'you', '代名詞：用於替換前面提到的單數物品。', '機器人不是人，請用 it。'),
('958ef92b-f394-5071-a837-a37491644bd7', '8fecc1f7-8571-4e65-874e-7bec724d9609', '___ students who finished the exam early were allowed to leave.', '提前完成考試的學生被允許離開。', 'The', 'A', 'Some', 'Any', '定冠詞 (Definite Article)', '指特定的那群人或事物用 the'),
('4c01b98e-e4df-5705-9812-5856968f0483', '5d20b73d-7d29-498d-92b3-52636f5571d1', '___ I use your phone?', '我可以使用你的電話嗎？', 'Can', 'Must', 'Will', 'Should', '用於請求許可。', '可以用 can 來請求許可。'),
('5f10878b-742a-53e2-89b5-cacb531427bb', '6de21873-0b3a-4a85-96c8-30ec0e0d91ea', '___ am a boy.', '我是一個男孩。', 'I', 'He', 'She', 'You', 'I 是第一人稱單數主格。', '單獨一個 I 就是「我」。'),
('0fcda612-c313-5625-8254-df4b28c8b09b', '69c72296-40c5-4d3c-8b3a-6a62df6576c3', 'I am very proud of ___ achievements in the recent competition.', '我為我在最近比賽中的成就感到非常自豪。', 'my', 'your', 'her', 'their', '所有格形容詞 (possessive adjective)', 'my + 名詞 → 我的...'),
('99e0d4ed-f8db-57e3-ae2c-16a6a84d4d8b', 'a6a15ed6-6715-4012-aca0-d203810bc834', 'I will never forget ___ moment of my life.', '我永遠不會忘記生命中的這個時刻。', 'this', 'any', 'each', 'some', '形容詞，用來修飾名詞，指代特定的時刻。', '指點眼前的東西用 this。');
